// GitHub Universal Router — RESOURCE + OPERATION -> URL + METHOD + BODY
const item = $input.first().json;
const BASE  = item.BASE_URL  || 'https://api.github.com';
const OWNER = item.OWNER || '';
const REPO  = item.REPO  || '';
const ORG   = item.ORG   || '';
const TOKEN = item.GITHUB_TOKEN || '';
const RES   = item.RESOURCE  || '';
const OP    = item.OPERATION || '';
const EXTRA = (() => { try { return JSON.parse(item.EXTRA_PARAMS||'{}'); } catch{return {};} })();

function u(path) {
  return BASE + path
    .replace('{owner}',OWNER).replace('{repo}',REPO).replace('{org}',ORG)
    .replace(/\{([^}]+)\}/g,(_,k) => EXTRA[k]!==undefined ? EXTRA[k] : ':'+k);
}

const R = {
  authentication: {
    get_authenticated_user:{method:'GET',url:u('/user')},
    get_rate_limit:        {method:'GET',url:u('/rate_limit')},
    list_installations:    {method:'GET',url:u('/user/installations')}
  },
  oauth: {
    check_token: {method:'POST',  url:u('/applications/{client_id}/token'),body:{access_token:EXTRA.token}},
    reset_token: {method:'PATCH', url:u('/applications/{client_id}/token'),body:{access_token:EXTRA.token}},
    delete_token:{method:'DELETE',url:u('/applications/{client_id}/token'),body:{access_token:EXTRA.token}},
    list_grants: {method:'GET',   url:u('/applications/grants')},
    delete_grant:{method:'DELETE',url:u('/applications/grants/{grant_id}')}
