    get_tree:     {method:'GET', url:u('/repos/{owner}/{repo}/git/trees/{tree_sha}')+'?recursive=1'},
    create_tree:  {method:'POST',url:u('/repos/{owner}/{repo}/git/trees'),body:{base_tree:EXTRA.base_tree||'',tree:EXTRA.tree||[]}},
    get_commit:   {method:'GET', url:u('/repos/{owner}/{repo}/git/commits/{commit_sha}')},
    create_commit:{method:'POST',url:u('/repos/{owner}/{repo}/git/commits'),body:{message:EXTRA.message||'',tree:EXTRA.tree_sha||'',parents:EXTRA.parents||[]}},
    list_refs:    {method:'GET', url:u('/repos/{owner}/{repo}/git/refs')},
    get_ref:      {method:'GET', url:u('/repos/{owner}/{repo}/git/ref/{ref}')},
    create_ref:   {method:'POST',url:u('/repos/{owner}/{repo}/git/refs'),body:{ref:EXTRA.ref||'',sha:EXTRA.sha||''}},
    update_ref:   {method:'PATCH',url:u('/repos/{owner}/{repo}/git/refs/{ref}'),body:{sha:EXTRA.sha||'',force:false}},
    delete_ref:   {method:'DELETE',url:u('/repos/{owner}/{repo}/git/refs/{ref}')},
    create_tag:   {method:'POST',url:u('/repos/{owner}/{repo}/git/tags'),body:{tag:EXTRA.tag||'',message:EXTRA.message||'',object:EXTRA.sha||'',type:'commit'}}
  },
  orgs: {
    list_orgs:        {method:'GET',   url:u('/organizations')+'?per_page=30'},
    get_org:          {method:'GET',   url:u('/orgs/{org}')},
    update_org:       {method:'PATCH', url:u('/orgs/{org}'),body:EXTRA},
    list_members:     {method:'GET',   url:u('/orgs/{org}/members')+'?per_page=30'},
    remove_member:    {method:'DELETE',url:u('/orgs/{org}/members/{username}')},
    list_repos:       {method:'GET',   url:u('/orgs/{org}/repos')+'?type=all&sort=updated&per_page=30'},
    create_repo:      {method:'POST',  url:u('/orgs/{org}/repos'),body:{name:EXTRA.name||'new-repo',private:EXTRA.private!==false,auto_init:true}},
    list_invitations: {method:'GET',   url:u('/orgs/{org}/invitations')},
    create_invitation:{method:'POST',  url:u('/orgs/{org}/invitations'),body:{email:EXTRA.email||'',role:'direct_member'}},
    cancel_invitation:{method:'DELETE',url:u('/orgs/{org}/invitations/{invitation_id}')},
    list_webhooks:    {method:'GET',   url:u('/orgs/{org}/hooks')},
    create_webhook:   {method:'POST',  url:u('/orgs/{org}/hooks'),body:{name:'web',config:{url:EXTRA.webhook_url||'',content_type:'json'},events:EXTRA.events||['push'],active:true}},
    delete_webhook:   {method:'DELETE',url:u('/orgs/{org}/hooks/{hook_id}')},
    list_teams:       {method:'GET',   url:u('/orgs/{org}/teams')},
    create_team:      {method:'POST',  url:u('/orgs/{org}/teams'),body:{name:EXTRA.name||'',privacy:'closed'}},
    get_audit_log:    {method:'GET',   url:u('/orgs/{org}/audit-log')+'?per_page=30'}
  },
  secrets: {
