    repo_delete:    {method:'DELETE',url:u('/repos/{owner}/{repo}/actions/secrets/{secret_name}')},
    org_list:       {method:'GET',   url:u('/orgs/{org}/actions/secrets')},
    org_get_pubkey: {method:'GET',   url:u('/orgs/{org}/actions/secrets/public-key')},
    org_upsert:     {method:'PUT',   url:u('/orgs/{org}/actions/secrets/{secret_name}'),body:{encrypted_value:EXTRA.encrypted_value||'',key_id:EXTRA.key_id||'',visibility:'all'}},
    org_delete:     {method:'DELETE',url:u('/orgs/{org}/actions/secrets/{secret_name}')}
  },
  workflow_runs: {
    list_for_repo:    {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runs')+'?per_page=30'},
    list_for_workflow:{method:'GET',   url:u('/repos/{owner}/{repo}/actions/workflows/{workflow_id}/runs')},
    get:              {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runs/{run_id}')},
    delete:           {method:'DELETE',url:u('/repos/{owner}/{repo}/actions/runs/{run_id}')},
    cancel:           {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/cancel')},
    re_run:           {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/rerun')},
    re_run_failed:    {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/rerun-failed-jobs')},
    list_jobs:        {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/jobs')},
    delete_logs:      {method:'DELETE',url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/logs')},
    get_timing:       {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/timing')},
    list_artifacts:   {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/artifacts')},
    approve:          {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runs/{run_id}/approve')},
    list_workflows:   {method:'GET',   url:u('/repos/{owner}/{repo}/actions/workflows')},
    get_workflow:     {method:'GET',   url:u('/repos/{owner}/{repo}/actions/workflows/{workflow_id}')},
    enable_workflow:  {method:'PUT',   url:u('/repos/{owner}/{repo}/actions/workflows/{workflow_id}/enable')},
    disable_workflow: {method:'PUT',   url:u('/repos/{owner}/{repo}/actions/workflows/{workflow_id}/disable')},
    trigger_dispatch: {method:'POST',  url:u('/repos/{owner}/{repo}/actions/workflows/{workflow_id}/dispatches'),body:{ref:EXTRA.ref||'main',inputs:EXTRA.inputs||{}}}
  },
  hosted_runners: {
    list_for_org:    {method:'GET',   url:u('/orgs/{org}/actions/hosted-runners')},
    create_for_org:  {method:'POST',  url:u('/orgs/{org}/actions/hosted-runners'),body:{name:EXTRA.name||'r3-runner',image:{id:'ubuntu-24.04',source:'github'},runner_group_id:EXTRA.runner_group_id||1,size:EXTRA.size||'4-core',maximum_runners:EXTRA.maximum_runners||10}},
    get_for_org:     {method:'GET',   url:u('/orgs/{org}/actions/hosted-runners/{hosted_runner_id}')},
    update_for_org:  {method:'PATCH', url:u('/orgs/{org}/actions/hosted-runners/{hosted_runner_id}'),body:EXTRA},
    delete_for_org:  {method:'DELETE',url:u('/orgs/{org}/actions/hosted-runners/{hosted_runner_id}')},
    list_images:     {method:'GET',   url:u('/orgs/{org}/actions/hosted-runners/images')},
    list_platforms:  {method:'GET',   url:u('/orgs/{org}/actions/hosted-runners/platforms')},
    list_limits:     {method:'GET',   url:u('/orgs/{org}/actions/hosted-runners/limits')},
    list_machine_sizes:{method:'GET', url:u('/orgs/{org}/actions/hosted-runners/machine-sizes')}
  },
  self_hosted_runners: {
    list_repo:         {method:'GET',   url:u('/repos/{owner}/{repo}/actions/runners')},
    create_jit_repo:   {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runners/generate-jitconfig'),body:{name:EXTRA.name||'r3-self',runner_group_id:EXTRA.runner_group_id||1,labels:EXTRA.labels||['self-hosted']}},
    reg_token_repo:    {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runners/registration-token')},
    remove_token_repo: {method:'POST',  url:u('/repos/{owner}/{repo}/actions/runners/remove-token')},
