    set_repos_for_group:      {method:'PUT',   url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/repositories'),body:{selected_repository_ids:EXTRA.repo_ids||[]}},
    add_repo_to_group:        {method:'PUT',   url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/repositories/{repository_id}')},
    remove_repo_from_group:   {method:'DELETE',url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/repositories/{repository_id}')},
    list_runners_for_group:   {method:'GET',   url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/runners')},
    add_runner_to_group:      {method:'PUT',   url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/runners/{runner_id}')},
    remove_runner_from_group: {method:'DELETE',url:u('/orgs/{org}/actions/runner-groups/{runner_group_id}/runners/{runner_id}')}
  },
  codespaces: {
    list:             {method:'GET',   url:u('/user/codespaces')},
    create:           {method:'POST',  url:u('/user/codespaces'),body:{repository_id:EXTRA.repository_id||0,ref:EXTRA.ref||'main',location:EXTRA.location||'EuropeWest',machine:EXTRA.machine||'basicLinux32gb',display_name:EXTRA.display_name||''}},
    list_for_repo:    {method:'GET',   url:u('/repos/{owner}/{repo}/codespaces')},
    create_for_repo:  {method:'POST',  url:u('/repos/{owner}/{repo}/codespaces'),body:{ref:EXTRA.ref||'main',machine:EXTRA.machine||'basicLinux32gb'}},
    get:              {method:'GET',   url:u('/user/codespaces/{codespace_name}')},
    update:           {method:'PATCH', url:u('/user/codespaces/{codespace_name}'),body:EXTRA},
    delete:           {method:'DELETE',url:u('/user/codespaces/{codespace_name}')},
    start:            {method:'POST',  url:u('/user/codespaces/{codespace_name}/start')},
    stop:             {method:'POST',  url:u('/user/codespaces/{codespace_name}/stop')},
    export:           {method:'POST',  url:u('/user/codespaces/{codespace_name}/exports')},
    list_machines:    {method:'GET',   url:u('/user/codespaces/{codespace_name}/machines')},
    list_secrets:     {method:'GET',   url:u('/user/codespaces/secrets')},
    get_pubkey:       {method:'GET',   url:u('/user/codespaces/secrets/public-key')},
    upsert_secret:    {method:'PUT',   url:u('/user/codespaces/secrets/{secret_name}'),body:{encrypted_value:EXTRA.encrypted_value||'',key_id:EXTRA.key_id||''}},
    delete_secret:    {method:'DELETE',url:u('/user/codespaces/secrets/{secret_name}')},
    org_list_secrets: {method:'GET',   url:u('/orgs/{org}/codespaces/secrets')},
    org_upsert_secret:{method:'PUT',   url:u('/orgs/{org}/codespaces/secrets/{secret_name}'),body:{encrypted_value:EXTRA.encrypted_value||'',key_id:EXTRA.key_id||'',visibility:'all'}}
