if (!R[RES]) return [{json:{error:`Unknown resource: "${RES}". Valid: ${Object.keys(R).join(', ')}`}}];
if (!R[RES][OP]) return [{json:{error:`Unknown op: "${OP}" for "${RES}". Valid: ${Object.keys(R[RES]).join(', ')}`}}];
const route = R[RES][OP];
return [{json:{
  method:route.method, url:route.url, body:route.body||null,
  headers:{Authorization:`Bearer ${TOKEN}`,Accept:'application/vnd.github+json','X-GitHub-Api-Version':'2022-11-28','Content-Type':'application/json'},
  resource:RES, operation:OP
}}];
